import{_ as a,H as s,f as n,i as e}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"容量估算","description":"","frontmatter":{},"headers":[],"relativePath":"systemDesign/02-容量估算.md","filePath":"systemDesign/02-容量估算.md","lastUpdated":1778496697000}'),d={name:"systemDesign/02-容量估算.md"};function o(p,t,l,r,i,h){return s(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="容量估算" tabindex="-1">容量估算 <a class="header-anchor" href="#容量估算" aria-label="Permalink to &quot;容量估算&quot;">​</a></h1><p>容量估算是系统设计里<strong>最被低估的硬功夫</strong>。新手以为「估算」就是问前辈一句「咱们有多少 QPS」,真正的工程师是<strong>张嘴就能算出 1 亿 DAU 的微博需要多少 MySQL、多少 Redis、多少带宽</strong>。这种心算不是为了显摆,是为了<strong>在没有数据的情况下做架构决策</strong>——面试时面试官不会给你 QPS,真实工作里产品也不会,但你必须立刻判断「这个量级要不要分库」「要不要上 CDN」。</p><blockquote><p>一句话先记住:<strong>估算是 30 秒内算出&quot;数量级&quot;</strong>——不是精确到 1234 QPS,是判断&quot;这是 1 千、1 万还是 100 万&quot;。<strong>数量级错一个,整个架构就错</strong>——单机能扛 1 万 QPS,你估成 100 万就上了 K8s + 100 节点 Redis 集群,<strong>钱白烧;反过来你估成 1 千,真上线就直接打挂</strong>。这一篇教的是&quot;建立数字直觉&quot;,看完之后听到 DAU 你脑子里应该自动蹦出 QPS。</p></blockquote><hr><h2 id="一、估算需要的「数字背诵表」" tabindex="-1">一、估算需要的「数字背诵表」 <a class="header-anchor" href="#一、估算需要的「数字背诵表」" aria-label="Permalink to &quot;一、估算需要的「数字背诵表」&quot;">​</a></h2><p>任何估算都从这几个常识开始,<strong>不背下来就不可能算得快</strong>:</p><h3 id="_1-1-时间换算" tabindex="-1">1.1 时间换算 <a class="header-anchor" href="#_1-1-时间换算" aria-label="Permalink to &quot;1.1 时间换算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 天 = 86,400 秒  ≈ 100,000 秒(估算时常用 10^5)</span></span>
<span class="line"><span>1 小时 = 3,600 秒  ≈ 4,000 秒(估算时常用 4 × 10^3)</span></span>
<span class="line"><span>1 个月 ≈ 2.5 × 10^6 秒</span></span>
<span class="line"><span>1 年 ≈ 3 × 10^7 秒</span></span></code></pre></div><blockquote><p><strong>最重要的就是&quot;一天 ≈ 10^5 秒&quot;这一条</strong>。99% 的 DAU → QPS 估算都用得上。</p></blockquote><h3 id="_1-2-数据量换算" tabindex="-1">1.2 数据量换算 <a class="header-anchor" href="#_1-2-数据量换算" aria-label="Permalink to &quot;1.2 数据量换算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 KB    = 10^3  字节</span></span>
<span class="line"><span>1 MB    = 10^6  字节</span></span>
<span class="line"><span>1 GB    = 10^9  字节</span></span>
<span class="line"><span>1 TB    = 10^12 字节</span></span>
<span class="line"><span>1 PB    = 10^15 字节</span></span></code></pre></div><h3 id="_1-3-网络与硬件性能-单机典型值" tabindex="-1">1.3 网络与硬件性能(单机典型值) <a class="header-anchor" href="#_1-3-网络与硬件性能-单机典型值" aria-label="Permalink to &quot;1.3 网络与硬件性能(单机典型值)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>延迟</th><th>直觉</th></tr></thead><tbody><tr><td>L1 cache</td><td>0.5 ns</td><td>同机指令级</td></tr><tr><td>主存随机访问</td><td>100 ns</td><td>同机内存级</td></tr><tr><td>SSD 随机读</td><td>100 μs</td><td>千分之一毫秒</td></tr><tr><td>千兆网络(同机房)</td><td>0.5 ms</td><td>半毫秒</td></tr><tr><td>跨机房(同城)</td><td>1-3 ms</td><td>几毫秒</td></tr><tr><td>跨地域(中美)</td><td>100-200 ms</td><td>100 毫秒级</td></tr><tr><td>HDD 随机读</td><td>10 ms</td><td>慢 100 倍</td></tr></tbody></table><table tabindex="0"><thead><tr><th>组件</th><th>单机吞吐量(粗略)</th></tr></thead><tbody><tr><td>Nginx 反向代理</td><td>5-10 万 QPS</td></tr><tr><td>Spring Boot 单实例</td><td>1000-5000 QPS</td></tr><tr><td>Redis 单实例</td><td>10 万 QPS</td></tr><tr><td>MySQL 单实例(读)</td><td>5000-10000 QPS</td></tr><tr><td>MySQL 单实例(写)</td><td>1000-3000 QPS</td></tr><tr><td>Kafka 单分区</td><td>100MB/s 顺序写</td></tr></tbody></table><blockquote><p>这两张表是<strong>估算的基石</strong>。看到「单机 MySQL 撑写 10 万 QPS」就立刻知道「不可能,得分库」——这种直觉就是凭这张表。</p></blockquote><hr><h2 id="二、dau-→-qps-的标准心算" tabindex="-1">二、DAU → QPS 的标准心算 <a class="header-anchor" href="#二、dau-→-qps-的标准心算" aria-label="Permalink to &quot;二、DAU → QPS 的标准心算&quot;">​</a></h2><p>最高频的估算场景:用户给了 DAU,你要快速算出<strong>平均 QPS</strong> 和<strong>峰值 QPS</strong>。</p><h3 id="_2-1-万能公式" tabindex="-1">2.1 万能公式 <a class="header-anchor" href="#_2-1-万能公式" aria-label="Permalink to &quot;2.1 万能公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>平均 QPS = DAU × 人均请求数 / 86400</span></span>
<span class="line"><span>       ≈ DAU × 人均请求数 / 10^5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>峰值 QPS = 平均 QPS × 峰均比 (一般 3 ~ 10 倍,常用 5 倍)</span></span></code></pre></div><h3 id="_2-2-几个常见数量级的肌肉记忆" tabindex="-1">2.2 几个常见数量级的肌肉记忆 <a class="header-anchor" href="#_2-2-几个常见数量级的肌肉记忆" aria-label="Permalink to &quot;2.2 几个常见数量级的肌肉记忆&quot;">​</a></h3><table tabindex="0"><thead><tr><th>DAU</th><th>人均 50 次</th><th>平均 QPS</th><th>峰值 QPS(×5)</th><th>数量级判断</th></tr></thead><tbody><tr><td>1 万</td><td>50 万</td><td>~6</td><td>30</td><td>单机随便</td></tr><tr><td>10 万</td><td>500 万</td><td>~60</td><td>300</td><td>单机轻松</td></tr><tr><td>100 万</td><td>5000 万</td><td>~600</td><td>3000</td><td>单机紧张,要做读写分离</td></tr><tr><td>1000 万</td><td>5 亿</td><td>~6000</td><td>3 万</td><td>必须分库 + 缓存</td></tr><tr><td>1 亿</td><td>50 亿</td><td>~6 万</td><td>30 万</td><td>必须分布式 + 多机房</td></tr><tr><td>10 亿(微信)</td><td>500 亿</td><td>~60 万</td><td>300 万</td><td>顶级架构,异地多活</td></tr></tbody></table><blockquote><p>把这张表<strong>背下来</strong>,以后听到 DAU 直接报出 QPS 数量级。<strong>面试时面试官给你 DAU 1 亿,你 3 秒内说&quot;峰值大概 30 万 QPS,单 MySQL 肯定扛不住,要分库 + Redis 缓存 + 异步写&quot;</strong>——比任何花哨答案都让人佩服。</p></blockquote><h3 id="_2-3-读写比例" tabindex="-1">2.3 读写比例 <a class="header-anchor" href="#_2-3-读写比例" aria-label="Permalink to &quot;2.3 读写比例&quot;">​</a></h3><p>不要一概用 50 次/天,<strong>根据业务调整读写比</strong>:</p><table tabindex="0"><thead><tr><th>业务类型</th><th>读写比(读:写)</th><th>说明</th></tr></thead><tbody><tr><td>微博 / Twitter</td><td>1000:1</td><td>每个人发 5 条,看 5000 条</td></tr><tr><td>朋友圈</td><td>100:1</td><td>看比发多</td></tr><tr><td>即时通讯</td><td>1:1</td><td>收发对等</td></tr><tr><td>电商商品页</td><td>100:1</td><td>看的多买的少</td></tr><tr><td>秒杀活动</td><td>10:1</td><td>极端读写都高</td></tr><tr><td>监控 / 日志</td><td>1:100</td><td>写多读少</td></tr></tbody></table><blockquote><p><strong>写少的系统优化读(加缓存、CDN)</strong>;<strong>写多的系统优化写(分库、批写、MQ 削峰)</strong>。<strong>搞反了等于白搭</strong>——给一个写多读少的日志系统加 Redis 缓存,完全是浪费钱。</p></blockquote><hr><h2 id="三、存储估算" tabindex="-1">三、存储估算 <a class="header-anchor" href="#三、存储估算" aria-label="Permalink to &quot;三、存储估算&quot;">​</a></h2><h3 id="_3-1-单条记录的尺寸感" tabindex="-1">3.1 单条记录的尺寸感 <a class="header-anchor" href="#_3-1-单条记录的尺寸感" aria-label="Permalink to &quot;3.1 单条记录的尺寸感&quot;">​</a></h3><table tabindex="0"><thead><tr><th>数据</th><th>平均尺寸</th><th>备注</th></tr></thead><tbody><tr><td>用户基本信息(name / email / age)</td><td>1 KB</td><td>含索引</td></tr><tr><td>一条微博文本</td><td>200 B</td><td>140 字符 + 元数据</td></tr><tr><td>一条评论</td><td>200 B</td><td>同上</td></tr><tr><td>一张缩略图</td><td>50 KB</td><td>压缩后</td></tr><tr><td>一张原图</td><td>1-5 MB</td><td></td></tr><tr><td>一秒视频(720p)</td><td>200 KB</td><td>压缩后</td></tr><tr><td>一秒视频(1080p)</td><td>500 KB</td><td></td></tr><tr><td>一秒直播(720p)</td><td>100-200 KB</td><td>实时编码低码率</td></tr><tr><td>一行日志</td><td>500 B</td><td>含时间戳和元数据</td></tr></tbody></table><h3 id="_3-2-存储估算心算" tabindex="-1">3.2 存储估算心算 <a class="header-anchor" href="#_3-2-存储估算心算" aria-label="Permalink to &quot;3.2 存储估算心算&quot;">​</a></h3><p><strong>例题</strong>:微博 1 亿 DAU,人均发 1 条,留存 5 年,要多少存储?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>日新增条数 = 1 亿</span></span>
<span class="line"><span>日新增字节 = 1 亿 × 200B = 2 × 10^10 = 20 GB</span></span>
<span class="line"><span>年新增 = 20 GB × 365 ≈ 7 TB</span></span>
<span class="line"><span>5 年 = 35 TB</span></span></code></pre></div><p><strong>带索引、副本、备份</strong>通常翻 3-5 倍:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>35 TB × 3 = 100 TB 量级</span></span></code></pre></div><blockquote><p>看起来吓人,<strong>实际上单机 NVMe 也能塞 30 TB,所以微博文本数据其实不大,真正占空间的是图片、视频</strong>——下面 3.3 看图片。</p></blockquote><h3 id="_3-3-图片-视频存储" tabindex="-1">3.3 图片 / 视频存储 <a class="header-anchor" href="#_3-3-图片-视频存储" aria-label="Permalink to &quot;3.3 图片 / 视频存储&quot;">​</a></h3><p><strong>例题</strong>:抖音 5 亿 DAU,人均看 50 条短视频,人均上传 1 条,平均时长 30 秒。</p><p>视频存储(写):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>日新增 = 5 亿 × 1 = 5 亿条 × 30 秒 × 200 KB/秒</span></span>
<span class="line"><span>     = 5 × 10^8 × 30 × 2 × 10^5</span></span>
<span class="line"><span>     = 3 × 10^15 字节</span></span>
<span class="line"><span>     = 3 PB / 天</span></span>
<span class="line"><span>年:3 PB × 365 ≈ 1 EB</span></span></code></pre></div><blockquote><p>看到这个数字就明白<strong>为什么短视频公司必须自建对象存储 + CDN 边缘节点</strong>——一年存 1 EB,公有云 OSS 一年光存储费就是几亿美元。这就是估算的力量,<strong>没估算就理解不了为什么字节、快手要自建机房</strong>。</p></blockquote><h3 id="_3-4-数据库行数估算" tabindex="-1">3.4 数据库行数估算 <a class="header-anchor" href="#_3-4-数据库行数估算" aria-label="Permalink to &quot;3.4 数据库行数估算&quot;">​</a></h3><p><strong>例题</strong>:微博的 follow 表多大?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 亿用户,人均关注 200 人</span></span>
<span class="line"><span>follow 表行数 = 1 亿 × 200 = 2 × 10^10 = 200 亿行</span></span></code></pre></div><blockquote><p><strong>MySQL 单表 5000 万行是公认上限</strong>,200 亿行 → 必须分 400 表(每表 5000 万)。这个数字直接决定「Follow 服务必须分库分表 + 引入分布式 ID」——没估算就想不到这一步。</p></blockquote><hr><h2 id="四、带宽估算" tabindex="-1">四、带宽估算 <a class="header-anchor" href="#四、带宽估算" aria-label="Permalink to &quot;四、带宽估算&quot;">​</a></h2><h3 id="_4-1-公式" tabindex="-1">4.1 公式 <a class="header-anchor" href="#_4-1-公式" aria-label="Permalink to &quot;4.1 公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>带宽(bps) = QPS × 单次响应大小(bit) × 8</span></span></code></pre></div><h3 id="_4-2-几个例子" tabindex="-1">4.2 几个例子 <a class="header-anchor" href="#_4-2-几个例子" aria-label="Permalink to &quot;4.2 几个例子&quot;">​</a></h3><p><strong>微博首页 timeline,一次请求返回 20 条 = 20 × 200B = 4 KB</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>峰值 QPS 30 万 → 30 万 × 4 KB × 8 = 9.6 Gbps</span></span></code></pre></div><p><strong>抖音视频流,看一个 30 秒视频 = 30 × 200 KB = 6 MB</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>同时在线 1000 万,平均每人 1 分钟刷一个 → 同时下载约 5 万 QPS</span></span>
<span class="line"><span>5 万 × 6 MB × 8 = 2.4 Tbps</span></span></code></pre></div><blockquote><p>看到 Tbps 级别的带宽就立刻明白<strong>为什么必须 CDN</strong>——单机房出口带宽撑死 100 Gbps,2.4 Tbps 必须散到全球几百个 CDN 节点上分摊。<strong>这就是估算引导的架构决策</strong>。</p></blockquote><h3 id="_4-3-反向估算-从带宽预算反推-qps-上限" tabindex="-1">4.3 反向估算:从带宽预算反推 QPS 上限 <a class="header-anchor" href="#_4-3-反向估算-从带宽预算反推-qps-上限" aria-label="Permalink to &quot;4.3 反向估算:从带宽预算反推 QPS 上限&quot;">​</a></h3><p>例:你机房出口 10 Gbps,单次响应 4 KB,<strong>理论上能撑多少 QPS</strong>?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10 × 10^9 / (4 × 10^3 × 8) = 3 × 10^5 QPS</span></span></code></pre></div><blockquote><p><strong>超过这个数 → 必须 CDN 或多机房</strong>,没第二条路。这种反向估算在做容量规划时极其有用。</p></blockquote><hr><h2 id="五、缓存命中率与穿透估算" tabindex="-1">五、缓存命中率与穿透估算 <a class="header-anchor" href="#五、缓存命中率与穿透估算" aria-label="Permalink to &quot;五、缓存命中率与穿透估算&quot;">​</a></h2><p>加 Redis 缓存的本质是<strong>减少打到 DB 的 QPS</strong>。算缓存效果时这两个数最关键:</p><h3 id="_5-1-命中率-→-db-实际负载" tabindex="-1">5.1 命中率 → DB 实际负载 <a class="header-anchor" href="#_5-1-命中率-→-db-实际负载" aria-label="Permalink to &quot;5.1 命中率 → DB 实际负载&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DB 实际 QPS = 总 QPS × (1 - 命中率)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>缓存命中率</th><th>总 QPS = 10 万</th><th>DB 实际 QPS</th></tr></thead><tbody><tr><td>50%</td><td>10 万</td><td>5 万</td></tr><tr><td>80%</td><td>10 万</td><td>2 万</td></tr><tr><td>95%</td><td>10 万</td><td>5000</td></tr><tr><td>99%</td><td>10 万</td><td>1000</td></tr><tr><td>99.9%</td><td>10 万</td><td>100</td></tr></tbody></table><blockquote><p>工程上<strong>95% 是基本合格,99% 是优秀,99.9% 是极致</strong>。<strong>命中率从 95% 提升到 99%,DB 负载降 5 倍</strong>——这就是缓存调优的价值。</p></blockquote><h3 id="_5-2-缓存内存估算" tabindex="-1">5.2 缓存内存估算 <a class="header-anchor" href="#_5-2-缓存内存估算" aria-label="Permalink to &quot;5.2 缓存内存估算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>缓存大小 = 热点数据条数 × 单条大小 × 1.5(碎片 + overhead)</span></span></code></pre></div><p><strong>例</strong>:微博热门 timeline,1 亿用户,Top 20% 是热门,每用户 timeline 100 条 × 200 B:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2000 万 × 100 × 200 = 4 × 10^11 = 400 GB × 1.5 = 600 GB</span></span></code></pre></div><blockquote><p><strong>单台 Redis 撑死 256 GB(内存大了 RDB / AOF 慢)</strong>,所以要分片为 3-5 个实例的 Redis Cluster。<strong>没估算就理解不了&quot;为什么要 Redis Cluster 而不是单机 Redis&quot;</strong>。</p></blockquote><hr><h2 id="六、连接数与文件描述符" tabindex="-1">六、连接数与文件描述符 <a class="header-anchor" href="#六、连接数与文件描述符" aria-label="Permalink to &quot;六、连接数与文件描述符&quot;">​</a></h2><p>经常被忽略,但生产事故重灾区:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>长连接服务的连接数 = 同时在线用户数(每人一条 WS / TCP)</span></span>
<span class="line"><span>单机 Linux 默认 ulimit = 1024,需要调到 10 万级别</span></span>
<span class="line"><span>单机 IM 网关上限通常 5-10 万长连接(取决于 epoll 调优)</span></span></code></pre></div><p><strong>例</strong>:微信同时在线 5 亿,<strong>至少需要</strong> 5 亿 / 10 万 = <strong>5000 台 IM 网关</strong>。</p><blockquote><p>这个数字直接告诉你「微信不是几台机器扛起来的,是几千上万台机器堆出来的」。<strong>长连接服务的扩容靠机器数,不靠单机性能</strong>。</p></blockquote><hr><h2 id="七、估算的「五倍法则」" tabindex="-1">七、估算的「五倍法则」 <a class="header-anchor" href="#七、估算的「五倍法则」" aria-label="Permalink to &quot;七、估算的「五倍法则」&quot;">​</a></h2><p>工程上有几个经验倍数,记住能省事:</p><table tabindex="0"><thead><tr><th>场景</th><th>倍数</th><th>原因</th></tr></thead><tbody><tr><td>平均 → 峰值 QPS</td><td>× 5</td><td>高峰期(午饭、晚 8-10 点)集中流量</td></tr><tr><td>业务量 → 副本量</td><td>× 3</td><td>一主两从 / 多副本</td></tr><tr><td>数据 → 总存储</td><td>× 3-5</td><td>索引 + 副本 + 备份</td></tr><tr><td>当下 → 一年后</td><td>× 2-10</td><td>业务增长预留</td></tr><tr><td>设计容量 → 实际容量</td><td>× 2</td><td>Buffer,生产从不跑满</td></tr></tbody></table><blockquote><p>估算完原始数字,<strong>记得乘 buffer</strong>。一个常见错误是「按平均 QPS 设计容量」——上线一周就因为高峰打挂,然后慌忙扩容。<strong>所有真实生产系统都按 2-5 倍峰值 buffer 来设计</strong>。</p></blockquote><hr><h2 id="八、一道完整估算题-设计-twitter" tabindex="-1">八、一道完整估算题:设计 Twitter <a class="header-anchor" href="#八、一道完整估算题-设计-twitter" aria-label="Permalink to &quot;八、一道完整估算题:设计 Twitter&quot;">​</a></h2><p>「设计 Twitter,DAU 2 亿」——3 分钟内你应该能给出:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. QPS 估算</span></span>
<span class="line"><span>   - 读 timeline:DAU × 人均刷 100 次 = 200 亿次/天 ≈ 23 万 QPS,峰值 ~100 万 QPS</span></span>
<span class="line"><span>   - 发推:DAU × 人均发 0.5 条 = 1 亿条/天 ≈ 1200 QPS,峰值 ~6000 QPS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 存储估算</span></span>
<span class="line"><span>   - 推文:1 亿/天 × 300 B(含元数据) = 30 GB/天 = 11 TB/年</span></span>
<span class="line"><span>   - 含索引副本 ×3 = 30 TB+/年</span></span>
<span class="line"><span>   - Follow 关系:2 亿用户 × 平均关注 200 = 400 亿条 → 必须分表</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 带宽估算</span></span>
<span class="line"><span>   - 读 timeline 100 万 QPS × 一次返回 20 条 × 300 B</span></span>
<span class="line"><span>     = 6 GB/s = 48 Gbps → 必须 CDN</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 缓存</span></span>
<span class="line"><span>   - 活跃用户 timeline 进 Redis,2 亿 × 20% × 100 条 × 300 B</span></span>
<span class="line"><span>     = 1.2 TB → Redis Cluster 5+ 实例</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 架构判断</span></span>
<span class="line"><span>   - 30 万写入 QPS 不算高,核心难点是 100 万读 → 必须 Push 模型预计算 timeline</span></span>
<span class="line"><span>   - 大 V 单独处理(Pull),不能 fanout 几千万次</span></span></code></pre></div><blockquote><p><strong>这一段就是 Twitter 设计的&quot;前 5 分钟&quot;</strong>——后面的方案细节都建立在这些数字上。<strong>面试官听完这段,基本就知道你能不能上 P7</strong>。</p></blockquote><hr><h2 id="九、踩坑提醒" tabindex="-1">九、踩坑提醒 <a class="header-anchor" href="#九、踩坑提醒" aria-label="Permalink to &quot;九、踩坑提醒&quot;">​</a></h2><ol><li><strong>不区分平均 QPS 和峰值 QPS</strong>——容量按峰值算,成本按平均算</li><li><strong>拍脑袋写&quot;我们 QPS 1 万&quot;</strong>——必须从 DAU + 行为推导,<strong>不要直接给 QPS</strong>,容易错一个量级</li><li><strong>忽略带宽</strong>——很多系统是带宽先到天花板,不是 CPU</li><li><strong>存储忘了乘副本和索引</strong>——3-5 倍 buffer 跑不掉</li><li><strong>算缓存按总数据量,不按热点</strong>——80/20 法则,只有 20% 热点要进缓存</li><li><strong>忽略长连接的 fd 上限</strong>——IM / 推送系统翻车主因</li><li><strong>不算&quot;一年后&quot;</strong>——按当下设计,半年后就扩容血亏</li><li><strong>数量级错一位</strong>——这是新手最致命的错,<strong>反复用 10^5 = 一天秒数 校验</strong></li><li><strong>不写过程只给结果</strong>——面试时一定要把 DAU → QPS → 存储 → 带宽 这条链讲出来,<strong>结果不重要,推理重要</strong></li><li><strong>过度精确</strong>——估算就是数量级,「1.2345 万 QPS」纯属浪费时间,「~1 万」就够了</li></ol><hr><p>下一篇:<code>03-架构演进史.md</code>,从最原始的「Apache + PHP + MySQL」单机架构开始,一步一步看到「微服务 + Service Mesh + Cell 架构」,理解每一次升级<strong>到底是什么瓶颈逼出来的</strong>——而不是技术潮流。</p>`,93)])])}const b=a(d,[["render",o]]);export{g as __pageData,b as default};
